parameters.jsCode:
const d = $('Normalise Input1').first().json;
return [{
  json: {
    source:        d.source,
    source_id:     d.source_id,
    accounts:      d.accounts,
    reel_url:      d.reel_url,
    cover_url:     d.cover_url,
    title:         d.title,
    final_caption: $input.first().json.message.content
  }
}];

const d = $input.first().json;
const accounts = Array.isArray(d.accounts) ? d.accounts : JSON.parse(d.accounts || '[]');

return accounts.map(account => ({
  json: {
    source:        d.source,
    source_id:     d.source_id,
    account:       account,
    reel_url:      d.reel_url,
    cover_url:     d.cover_url,
    caption:       d.final_caption,
    title:         d.title
  }
}));

const items = $input.all();

return items.map(item => {
  const account = (item.json.account || '').toString().toLowerCase();

  let platform = 'unknown';

  if (account.includes('instagram')) platform = 'instagram';
  else if (account.includes('youtube')) platform = 'youtube';
  else if (account.includes('linkedin')) platform = 'linkedin';

  return {
    json: {
      ...item.json,
      platform
    }
  };
});

const upstream = $('IG: Create Reel Container1').first().json;
return [{
  json: {
    upload_status: 'posted',
    platform:      'instagram',
    account:       upstream.account,
    source:        upstream.source,
    source_id:     upstream.source_id,
    post_id:       $input.first().json.id || 'n/a',
    posted_at:     new Date().toISOString()
  }
}];

const upstream = $('YT: Upload Short1').first().json;
return [{
  json: {
    upload_status: 'posted',
    platform:      'youtube',
    account:       upstream.account,
    source:        upstream.source,
    source_id:     upstream.source_id,
    post_id:       $input.first().json.id || 'n/a',
    posted_at:     new Date().toISOString()
  }
}];

const upstream = $('LI: Post Video1').first().json;
return [{
  json: {
    upload_status: 'posted',
    platform:      'linkedin',
    account:       upstream.account,
    source:        upstream.source,
    source_id:     upstream.source_id,
    post_id:       $input.first().json.id || 'n/a',
    posted_at:     new Date().toISOString()
  }
}];

const e = $input.first().json;
const runData = e.execution?.data?.resultData?.runData;
const normNode = runData?.['Normalise Input']?.[0]?.data?.main?.[0]?.[0]?.json;
return [{
  json: {
    error_message: '❌ Upload failed | Workflow: ' + e.workflow.name + ' | Node: ' + e.execution.error.node.name + ' | ' + e.execution.error.message,
    source_id:     normNode?.source_id || 'unknown',
    source:        normNode?.source    || 'unknown'
  }
}];

// Current item = one account to post to (has .account and .platform)
const item = $json;

// Registry = all rows from Account Registry sheet
const registry = $('Fetch Account Registry').all().map(r => r.json);

// Find matching registry row
const match = registry.find(row =>
  row.account_name?.toLowerCase().trim() === item.account?.toLowerCase().trim()
  && row.active?.toLowerCase() === 'true'
);

if (!match) {
  // No registry entry — skip this account gracefully
  return {
    json: {
      ...item,
      _skip: true,
      _skip_reason: `Account '${item.account}' not found in registry or is inactive`
    }
  };
}

return {
  json: {
    ...item,
    _skip:        false,
    ig_user_id:   match.ig_user_id   || '',
    access_token: match.access_token || '',
    credential_name: match.credential_name || ''
  }
};

console.warn('⚠️ Skipped account:', $json.account, '|', $json._skip_reason);
// Optionally write back to sheet here
return { json: { skipped: true, account: $json.account, reason: $json._skip_reason } };

